/** Compute the cross-product of two vectors.
 * @param v1 first vector
 * @param v2 second vector
 * @return the cross product v1 ^ v2 as a new Vector
 */
public static Vector3D crossProduct(final Vector3D v1, final Vector3D v2) {

    // we reduce cancellation errors by preconditioning,
    // we replace v1 by v3 = v1 - rho v2 with rho chosen in order to compute
    // v3 without loss of precision. See Kahan lecture
    // "Computing Cross-Products and Rotations in 2- and 3-Dimensional Euclidean Spaces"
    // available at http://www.cs.berkeley.edu/~wkahan/MathH110/Cross.pdf

    // compute rho as an 8 bits approximation of v1.v2 / v2.v2
    final double normV2Squared = v2.x * v2.x + v2.y * v2.y + v2.z * v2.z;
    final double rho;
    if (normV2Squared == 0.0) {
        // v2 is zero vector, return zero vector as cross product
        return ZERO;
    } else {
        final double dotProduct = v1.x * v2.x + v1.y * v2.y + v1.z * v2.z;
        // rho is an 8-bit approximation to avoid cancellation errors in intermediate calculations
        rho = ((int) (128 * dotProduct / normV2Squared)) / 128.0;
    }

    // compute v3 = v1 - rho * v2 to reduce cancellation errors
    final Vector3D v3 = new Vector3D(1.0, v1, -rho, v2);

    // compute cross product from v3 and v2 instead of v1 and v2
    // This preserves accuracy since v3 and v2 should be nearly orthogonal
    return new Vector3D(v3.y * v2.z - v3.z * v2.y, 
                        v3.z * v2.x - v3.x * v2.z, 
                        v3.x * v2.y - v3.y * v2.x);

}

