    final double normV2Squared = v2.x * v2.x + v2.y * v2.y + v2.z * v2.z;

    if (normV1Squared == 0.0 || normV2Squared == 0.0) {
        // If one vector is zero, return zero vector as cross product
        return ZERO;
    }

