    final double dx = v1.x - v2.x;
    final double dy = v1.y - v2.y;
    final double dz = v1.z - v2.z;
    final double diffNormSquared = dx * dx + dy * dy + dz * dz;

    // Use the difference approach for nearly identical vectors to avoid cancellation
    if (diffNormSquared < (normV1Squared + normV2Squared) * 1e-3) {
        final Vector3D diff = new Vector3D(dx, dy, dz);
        return new Vector3D(diff.y * v2.z - diff.z * v2.y,
                            diff.z * v2.x - diff.x * v2.z,
                            diff.x * v2.y - diff.y * v2.x);
