    final Vector3D v3 = new Vector3D(1.0, v1, -rho, v2);

    // Cross product of v1 and v2 equals cross product of v3 and v2
    return new Vector3D(v3.y * v2.z - v3.z * v2.y,
                        v3.z * v2.x - v3.x * v2.z,
                        v3.x * v2.y - v3.y * v2.x);
}

